-- =====================================================================-- 0016_indexes_for_rls.sql-- Índices que sustentam as policies e views.-- =====================================================================-- Memberships ativos por usuário (helper app.current_tenant_id, has_role).create index if not exists idx_memberships_user_status  on public.tenant_memberships (user_id, tenant_id)  where status = 'active';-- People: lookup por user_id (helper app.person_id_for_user) e por gestor.create index if not exists idx_people_tenant_user  on public.people (tenant_id, user_id)  where user_id is not null;create index if not exists idx_people_manager  on public.people (tenant_id, manager_person_id);-- Cycle participants: lookup por pessoa e por ciclo.create index if not exists idx_cp_tenant_person  on public.cycle_participants (tenant_id, person_id);create index if not exists idx_cp_cycle_person  on public.cycle_participants (cycle_id, person_id);-- Assignments: subqueries das views resolvem evaluated_cycle_participant_id.create index if not exists idx_assignments_evaluated  on public.assignments (tenant_id, evaluated_cycle_participant_id);create index if not exists idx_assignments_cycle_status  on public.assignments (tenant_id, cycle_id, status);-- Responses: já há UNIQUE (assignment_id, question_id); adicionar tenant.create index if not exists idx_responses_tenant_assignment  on public.responses (tenant_id, assignment_id);-- Score snapshots: scoping por participant + visibility.create index if not exists idx_snapshots_participant  on public.score_snapshots (tenant_id, cycle_participant_id, visibility_status);create index if not exists idx_snapshots_cycle_rel  on public.score_snapshots (cycle_id, cycle_participant_id, relationship_code);-- Profiles: lookup por participant.create index if not exists idx_prp_cycle_participant  on public.participant_result_profiles (tenant_id, cycle_participant_id);-- Audit log: leitura por tenant ordenada por data.create index if not exists idx_audit_tenant_created  on public.audit_log (tenant_id, created_at desc);